from typing import List

def partitionToKEqualSumSubsets(data: str) -> bool:
    nums = list(map(int, data.split()[:-1]))
    k = int(data.split()[-1])

    total_sum = sum(nums)
    n = len(nums)

    if total_sum % k != 0:
        return False

    target_sum = total_sum // k
    subsets = [0] * k

    def can_partition(index: int) -> bool:
        if index == n:
            return all(x == target_sum for x in subsets)

        for i in range(k):
            if subsets[i] + nums[index] <= target_sum:
                subsets[i] += nums[index]
                if can_partition(index + 1):
                    return True
                subsets[i] -= nums[index]
            if subsets[i] == 0:
                break

        return False

    return can_partition(0)

