function partitionToKEqualSumSubsets(data) {
    const lines = data.split('\n');
    const nums = lines[0].split(' ').map(Number);
    const k = Number(lines[1]);

    const totalSum = nums.reduce((a, b) => a + b, 0);
    if (totalSum % k !== 0) return false;
    const targetSum = totalSum / k;
    const n = nums.length;
    const used = new Array(n).fill(false);

    function canPartition(startIndex, currentSum, count) {
        if (count === k - 1) return true;
        if (currentSum === targetSum) return canPartition(0, 0, count + 1);
        for (let i = startIndex; i < n; i++) {
            if (!used[i] && currentSum + nums[i] <= targetSum) {
                used[i] = true;
                if (canPartition(i + 1, currentSum + nums[i], count)) return true;
                used[i] = false;
            }
        }
        return false;
    }

    return canPartition(0, 0, 0);
}

