class Solution {
    public boolean partitionToKEqualSumSubsets(int[] data) {
        int n = data.length;
        if (n == 0) return false;
        int totalSum = 0;
        for (int num : data) {
            totalSum += num;
        }
        if (totalSum % 2 != 0) return false;
        int targetSum = totalSum / 2;
        boolean[] dp = new boolean[targetSum + 1];
        dp[0] = true;
        for (int num : data) {
            for (int j = targetSum; j >= num; j--) {
                dp[j] = dp[j] || dp[j - num];
            }
        }
        return dp[targetSum];
    }
}

