func backtrack(data []int, subsets []int, index int, target int) bool {
    if index == len(data) {
        for _, sum := range subsets {
            if sum != target {
                return false
            }
        }
        return true
    }

    for i := 0; i < len(subsets); i++ {
        if subsets[i]+data[index] <= target {
            subsets[i] += data[index]
            if backtrack(data, subsets, index+1, target) {
                return true
            }
            subsets[i] -= data[index]
        }
        if subsets[i] == 0 {
            break
        }
    }

    return false
}

